import { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, Popup, CircleMarker, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import { Trees, X, LocateFixed, Navigation, Map as MapIcon, Satellite, ExternalLink, Navigation2 } from 'lucide-react';

import { GeoSearchControl, OpenStreetMapProvider } from 'leaflet-geosearch';
import 'leaflet-geosearch/dist/geosearch.css';

// Fix leaflet default marker icons (broken in Vite/Webpack)
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
    iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
    iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
    shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
});

// ── Custom green marker icon (app spaces) ──────────────────────────────────────
function createGreenIcon(isSelected = false) {
    const size = isSelected ? 44 : 36;
    const svg = `
    <svg width="${size}" height="${size}" viewBox="0 0 44 44" fill="none" xmlns="http://www.w3.org/2000/svg">
      <circle cx="22" cy="22" r="20" fill="${isSelected ? '#4ade80' : '#22c55e'}" 
              stroke="white" stroke-width="3"
              ${isSelected ? 'filter="drop-shadow(0 0 8px rgba(74,222,128,0.8))"' : ''}/>
      <text x="50%" y="58%" dominant-baseline="middle" text-anchor="middle" 
            font-size="18" font-family="sans-serif">🌿</text>
    </svg>`;
    return L.divIcon({
        html: svg,
        className: '',
        iconSize: [size, size],
        iconAnchor: [size / 2, size / 2],
        popupAnchor: [0, -size / 2],
    });
}

// ── Nearby OSM places marker icon ──────────────────────────────────────────────
function createOsmIcon(emoji, isSelected = false) {
    const size = isSelected ? 36 : 28;
    const svg = `
    <svg width="${size}" height="${size}" viewBox="0 0 44 44" fill="none" xmlns="http://www.w3.org/2000/svg">
      <circle cx="22" cy="22" r="20" fill="${isSelected ? '#60a5fa' : '#3b82f6'}" 
              stroke="white" stroke-width="2"
              ${isSelected ? 'filter="drop-shadow(0 0 8px rgba(96,165,250,0.8))"' : ''}/>
      <text x="50%" y="58%" dominant-baseline="middle" text-anchor="middle" 
            font-size="18" font-family="sans-serif">${emoji}</text>
    </svg>`;
    return L.divIcon({
        html: svg,
        className: '',
        iconSize: [size, size],
        iconAnchor: [size / 2, size / 2],
        popupAnchor: [0, -size / 2],
    });
}

// ── Search Control ─────────────────────────────────────────────────────────────
function SearchControl() {
    const map = useMap();
    useEffect(() => {
        const provider = new OpenStreetMapProvider();
        const searchControl = new GeoSearchControl({
            provider,
            style: 'bar',
            showMarker: true,
            showPopup: false,
            autoClose: true,
            retainZoomLevel: false,
            animateZoom: true,
            searchLabel: 'Search any location...',
        });
        map.addControl(searchControl);
        return () => map.removeControl(searchControl);
    }, [map]);
    return null;
}

// ── Map pan/zoom controller ───────────────────────────────────────────────────
function MapController({ selectedSpace, userLocation, selectedNearby }) {
    const map = useMap();
    useEffect(() => {
        if (selectedSpace?.location) {
            map.flyTo([selectedSpace.location.lat, selectedSpace.location.lng], 15, { duration: 1 });
        }
    }, [selectedSpace, map]);

    useEffect(() => {
        if (selectedNearby?.location) {
            map.flyTo([selectedNearby.location.lat, selectedNearby.location.lng], 16, { duration: 1 });
        }
    }, [selectedNearby, map]);

    useEffect(() => {
        if (userLocation) {
            map.flyTo([userLocation.lat, userLocation.lng], 14, { duration: 1 });
        }
    }, [userLocation, map]);

    return null;
}

// ── Recenter button ───────────────────────────────────────────────────────────
function RecenterButton({ userLocation }) {
    const map = useMap();
    if (!userLocation) return null;
    return (
        <button
            onClick={() => map.flyTo([userLocation.lat, userLocation.lng], 14, { duration: 0.8 })}
            title="Recenter to my location"
            className="absolute bottom-6 right-4 z-[500] w-12 h-12 bg-white dark:bg-[#111a14] border border-gray-200 dark:border-green-900/40 rounded-full flex items-center justify-center shadow-lg text-green-600 dark:text-green-400 hover:bg-gray-50 dark:hover:bg-green-900/40 transition-colors"
        >
            <LocateFixed size={20} />
        </button>
    );
}

// ── Main MapView ──────────────────────────────────────────────────────────────
export default function MapView({ spaces, nearbySpaces = [], darkMode, userLocation, selectedSpace, selectedNearby, onMarkerClick, onNearbyMarkerClick }) {
    const [mapStyle, setMapStyle] = useState('terrain'); // 'terrain' or 'satellite'

    const defaultCenter = userLocation
        ? [userLocation.lat, userLocation.lng]
        : [20.5937, 78.9629]; // India default

    // Tile layers — map always uses standard tiles regardless of dark mode
    const terrainTile = 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png';
    const satelliteTile = 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}';

    const currentTileUrl = mapStyle === 'terrain' ? terrainTile : satelliteTile;
    const attribution = mapStyle === 'terrain'
        ? '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
        : '&copy; Esri &mdash; Source: Esri, i-cubed, USDA, USGS, AEX, GeoEye, Getmapping, Aerogrid, IGN, IGP, UPR-EGP, and the GIS User Community';

    return (
        <div id="map-container" className="w-full h-full relative" style={{ isolation: 'isolate', filter: 'none' }}>
            <MapContainer
                center={defaultCenter}
                zoom={12}
                style={{ width: '100%', height: '100%', zIndex: 0 }}
                zoomControl={true}
            >
                <TileLayer url={currentTileUrl} attribution={attribution} />

                <SearchControl />
                <MapController selectedSpace={selectedSpace} userLocation={userLocation} selectedNearby={selectedNearby} />
                <RecenterButton userLocation={userLocation} />

                {/* User location marker */}
                {userLocation && (
                    <CircleMarker
                        center={[userLocation.lat, userLocation.lng]}
                        radius={10}
                        pathOptions={{ color: '#3b82f6', fillColor: '#60a5fa', fillOpacity: 0.9, weight: 3 }}
                    />
                )}

                {/* App spaces markers */}
                {spaces.map((space) => (
                    <Marker
                        key={space._id}
                        position={[space.location.lat, space.location.lng]}
                        icon={createGreenIcon(selectedSpace?._id === space._id)}
                        eventHandlers={{ click: () => onMarkerClick(space) }}
                    >
                        <Popup maxWidth={270} className="green-popup">
                            <div className="w-64 rounded-xl overflow-hidden font-['Inter']">
                                {space.imageUrl ? (
                                    <img src={space.imageUrl} alt={space.name} loading="lazy"
                                        className="w-full h-32 object-cover" />
                                ) : (
                                    <div className="w-full h-20 bg-green-100 flex items-center justify-center">
                                        <Trees size={32} className="text-green-400" />
                                    </div>
                                )}
                                <div className="p-3 bg-white">
                                    <h3 className="font-semibold text-gray-900 text-base mb-1">{space.name}</h3>
                                    {space.area && <p className="text-xs text-gray-500 mb-2">📐 {space.area}</p>}
                                    {space.description && (
                                        <p className="text-xs text-gray-600 mb-3 line-clamp-2">{space.description}</p>
                                    )}
                                    <Link
                                        to={`/park/${space._id}`}
                                        className="block w-full text-center text-xs font-semibold py-2 px-3 mt-3
                                            rounded-lg bg-green-500 text-white hover:bg-green-600 transition-colors">
                                        View Details →
                                    </Link>
                                </div>
                            </div>
                        </Popup>
                    </Marker>
                ))}

                {/* Nearby OSM places markers */}
                {nearbySpaces.map((place) => (
                    <Marker
                        key={place.id}
                        position={[place.location.lat, place.location.lng]}
                        icon={createOsmIcon(place.emoji, selectedNearby?.id === place.id)}
                        eventHandlers={{ click: () => onNearbyMarkerClick?.(place) }}
                    >
                        <Popup className="green-popup">
                            <div className="px-2 py-1 flex flex-col items-center">
                                <span className="text-2xl mb-1">{place.emoji}</span>
                                <h3 className="font-bold text-gray-900 min-w-max text-sm">{place.name}</h3>
                                <p className="text-xs text-gray-500 font-medium">{place.type}</p>
                            </div>
                        </Popup>
                    </Marker>
                ))}
            </MapContainer>

            {/* ── Layer Toggle (Terrain/Satellite) ── */}
            <div className="absolute top-20 right-4 z-[500] flex flex-col gap-2">
                <button
                    onClick={() => setMapStyle('terrain')}
                    className={`w-10 h-10 rounded-xl shadow-lg flex items-center justify-center transition-all ${mapStyle === 'terrain'
                        ? 'bg-blue-500 text-white ring-2 ring-blue-300'
                        : 'bg-white text-gray-600 hover:bg-gray-50'
                        }`}
                    title="Terrain View"
                >
                    <MapIcon size={18} />
                </button>
                <button
                    onClick={() => setMapStyle('satellite')}
                    className={`w-10 h-10 rounded-xl shadow-lg flex items-center justify-center transition-all ${mapStyle === 'satellite'
                        ? 'bg-blue-500 text-white ring-2 ring-blue-300'
                        : 'bg-white text-gray-600 hover:bg-gray-50'
                        }`}
                    title="Satellite View"
                >
                    <Satellite size={18} />
                </button>
            </div>

            {/* ── Floating selected-nearby info panel ── */}
            {selectedNearby && (
                <div className="absolute bottom-6 left-4 z-[500] max-w-[280px] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden animate-fade-up">
                    <div className="bg-green-500 px-4 py-2.5 flex items-center gap-2">
                        <span className="text-xl">{selectedNearby.emoji}</span>
                        <div className="flex-1 min-w-0">
                            <p className="text-white font-bold text-sm leading-tight truncate">{selectedNearby.name}</p>
                            <p className="text-green-100 text-xs">{selectedNearby.type}</p>
                        </div>
                        {selectedNearby.distKm != null && (
                            <span className="text-xs text-green-100 font-medium flex-shrink-0">
                                {selectedNearby.distKm < 1
                                    ? `${Math.round(selectedNearby.distKm * 1000)} m`
                                    : `${selectedNearby.distKm.toFixed(1)} km`}
                            </span>
                        )}
                    </div>
                    <div className="px-4 py-2.5 flex items-center gap-3">
                        {selectedNearby.openingHours && (
                            <p className="text-xs text-gray-500 flex-1 truncate">🕐 {selectedNearby.openingHours}</p>
                        )}
                        {selectedNearby.website && (
                            <a href={selectedNearby.website} target="_blank" rel="noopener noreferrer"
                                className="flex items-center gap-1 text-xs text-green-600 hover:text-green-700 font-medium flex-shrink-0">
                                <ExternalLink size={11} /> Website
                            </a>
                        )}
                        {!selectedNearby.openingHours && !selectedNearby.website && (
                            <p className="text-xs text-gray-400">Click the marker for more info</p>
                        )}
                    </div>
                </div>
            )}

        </div>
    );
}

import { useState, useCallback } from 'react';
import { Search, Trees, ChevronLeft, ChevronRight, Loader2, RefreshCw, MapPin, ExternalLink } from 'lucide-react';
import SpaceCard from './SpaceCard';
import { useNearbyPlaces } from '../hooks/useNearbyPlaces';

const ALL_FACILITIES = [
    { id: 'playground', label: 'Playground', emoji: '🛝' },
    { id: 'walking_track', label: 'Walking Track', emoji: '🚶' },
    { id: 'garden', label: 'Garden', emoji: '🌸' },
    { id: 'benches', label: 'Benches', emoji: '🪑' },
    { id: 'sports_area', label: 'Sports Area', emoji: '⚽' },
];

const TYPE_EMOJI = {
    'Park': '🌳',
    'Garden': '🌸',
    'Forest': '🌲',
    'Nature Reserve': '🦋',
    'Recreation Ground': '⛳',
    'Green Space': '🌿',
};

function haversineKm(a, b) {
    if (!a || !b) return null;
    const R = 6371;
    const dLat = ((b.lat - a.lat) * Math.PI) / 180;
    const dLng = ((b.lng - a.lng) * Math.PI) / 180;
    const lat1 = (a.lat * Math.PI) / 180;
    const lat2 = (b.lat * Math.PI) / 180;
    const x = Math.sin(dLat / 2) ** 2 + Math.cos(lat1) * Math.cos(lat2) * Math.sin(dLng / 2) ** 2;
    return R * 2 * Math.atan2(Math.sqrt(x), Math.sqrt(1 - x));
}

function formatDist(km) {
    if (km === null) return null;
    return km < 1 ? `${Math.round(km * 1000)} m` : `${km.toFixed(1)} km`;
}

/** Small card for OSM nearby places — different from app SpaceCard */
function NearbyPlaceCard({ place, darkMode, onClick, isSelected }) {
    return (
        <div
            onClick={onClick}
            role="button"
            tabIndex={0}
            onKeyDown={(e) => e.key === 'Enter' && onClick()}
            className={`group flex items-center gap-3 px-3 py-2.5 rounded-xl cursor-pointer transition-all duration-200 border
                ${isSelected
                    ? darkMode ? 'bg-green-900/50 border-green-500/60' : 'bg-green-50 border-green-400'
                    : darkMode ? 'border-green-900/30 hover:border-green-700/50 hover:bg-green-900/20'
                        : 'border-gray-100 hover:border-green-200 hover:bg-gray-50'
                }`}
        >
            {/* Icon circle */}
            <div className={`w-9 h-9 flex-shrink-0 rounded-full flex items-center justify-center text-lg
                ${darkMode ? 'bg-green-900/40' : 'bg-green-50'}`}>
                {place.emoji}
            </div>

            {/* Text */}
            <div className="flex-1 min-w-0">
                <div className="flex items-start justify-between gap-1">
                    <p className={`text-sm font-semibold leading-tight truncate
                        ${darkMode ? 'text-green-100' : 'text-gray-900'}`}>
                        {place.name}
                    </p>
                    {place.distKm !== null && (
                        <span className="flex-shrink-0 text-xs text-green-500 font-medium">
                            {formatDist(place.distKm)}
                        </span>
                    )}
                </div>
                <p className={`text-[11px] mt-0.5 ${darkMode ? 'text-green-600' : 'text-gray-400'}`}>
                    {place.type}
                </p>
            </div>
        </div>
    );
}

/**
 * Sidebar – Two sections:
 *   1. "Your Spaces" — spaces added to the app (from server)
 *   2. "Nearby in OSM" — real parks/forests/gardens from OpenStreetMap
 */
export default function Sidebar({
    spaces, userLocation, selectedSpace, onSelect,
    activeFilters, onFilterChange, darkMode, onNearbyClick,
    nearbyPlaces, nearbyLoading, nearbyError, refetchNearby,
    selectedNearby
}) {
    const [search, setSearch] = useState('');
    const [collapsed, setCollapsed] = useState(false);
    const [activeTab, setActiveTab] = useState('nearby'); // 'app' | 'nearby'

    // ── Filter app spaces by facilities & search ─────────────────────────────
    const filtered = spaces
        .filter((s) => activeFilters.size === 0 || [...activeFilters].every((f) => s.facilities.includes(f)))
        .filter((s) => search === '' || s.name.toLowerCase().includes(search.toLowerCase()))
        .map((s) => ({ ...s, distKm: haversineKm(userLocation, s.location) }))
        .sort((a, b) => (a.distKm ?? Infinity) - (b.distKm ?? Infinity));

    // ── Filter OSM places by search ───────────────────────────────────────────
    const filteredNearby = nearbyPlaces.filter((p) =>
        search === '' || p.name.toLowerCase().includes(search.toLowerCase())
    );

    const toggleFilter = (id) => {
        const next = new Set(activeFilters);
        next.has(id) ? next.delete(id) : next.add(id);
        onFilterChange(next);
    };

    const base = darkMode
        ? 'bg-[#111a14] border-green-900/40 text-green-100'
        : 'bg-white border-gray-100 text-gray-900';

    const tabBase = (active) => active
        ? darkMode ? 'bg-green-600 text-white shadow-sm' : 'bg-green-500 text-white shadow-sm'
        : darkMode ? 'text-green-400 hover:bg-green-900/30' : 'text-gray-500 hover:bg-gray-200';

    return (
        <aside className={`relative flex flex-col transition-all duration-300 border-r ${base}
            ${collapsed ? 'w-12' : 'w-72 xl:w-80'}`}>

            {/* Collapse toggle */}
            <button
                onClick={() => setCollapsed((p) => !p)}
                className={`absolute -right-3.5 top-5 z-10 w-7 h-7 rounded-full flex items-center justify-center
                    shadow-md border transition-colors
                    ${darkMode ? 'bg-[#1a2a1e] border-green-800 text-green-400 hover:bg-green-900'
                        : 'bg-white border-green-200 text-green-600 hover:bg-green-50'}`}>
                {collapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
            </button>

            {collapsed && (
                <div className="flex flex-col items-center pt-5 gap-3">
                    <Trees size={20} className="text-green-500" />
                </div>
            )}

            {!collapsed && (
                <>
                    {/* Header */}
                    <div className={`px-4 pt-4 pb-3 border-b ${darkMode ? 'border-green-900/40' : 'border-gray-100'}`}>
                        <h2 className="font-bold text-base flex items-center gap-2 mb-3">
                            <Trees size={16} className="text-green-500" />
                            Green Spaces
                            <span className={`ml-auto text-xs font-medium px-2 py-0.5 rounded-full
                                ${darkMode ? 'bg-green-900/50 text-green-400' : 'bg-green-100 text-green-700'}`}>
                                {activeTab === 'nearby' ? filteredNearby.length : filtered.length}
                            </span>
                        </h2>

                        {/* Tab switcher */}
                        <div className={`flex gap-1 p-1 rounded-xl mb-3 ${darkMode ? 'bg-green-900/20' : 'bg-gray-100'}`}>
                            <button
                                onClick={() => setActiveTab('nearby')}
                                className={`flex-1 text-xs font-semibold py-1.5 rounded-lg transition-all ${tabBase(activeTab === 'nearby')}`}>
                                🗺️ Nearby Places
                            </button>
                            <button
                                onClick={() => setActiveTab('app')}
                                className={`flex-1 text-xs font-semibold py-1.5 rounded-lg transition-all ${tabBase(activeTab === 'app')}`}>
                                📌 My Spaces ({spaces.length})
                            </button>
                        </div>

                        {/* Search */}
                        <div className={`flex items-center gap-2 px-3 py-2 rounded-xl border text-sm
                            ${darkMode ? 'bg-[#0a1a0e] border-green-900/40 placeholder:text-green-800'
                                : 'bg-gray-50 border-gray-200'}`}>
                            <Search size={14} className="text-green-500 flex-shrink-0" />
                            <input
                                type="text"
                                placeholder="Search spaces..."
                                value={search}
                                onChange={(e) => setSearch(e.target.value)}
                                className="flex-1 bg-transparent border-none outline-none text-sm"
                            />
                        </div>

                        {/* Filter chips — only shown in app tab */}
                        {activeTab === 'app' && (
                            <div className="flex flex-wrap gap-1.5 mt-3">
                                {ALL_FACILITIES.map((f) => {
                                    const active = activeFilters.has(f.id);
                                    return (
                                        <button key={f.id} onClick={() => toggleFilter(f.id)}
                                            className={`text-xs px-2.5 py-1 rounded-full border font-medium transition-all duration-150
                                                ${active ? 'bg-green-500 border-green-500 text-white shadow'
                                                    : darkMode ? 'bg-green-900/20 border-green-800/50 text-green-400 hover:border-green-600'
                                                        : 'bg-gray-50 border-gray-200 text-gray-600 hover:border-green-300 hover:text-green-700'}`}>
                                            {f.emoji} {f.label}
                                        </button>
                                    );
                                })}
                                {activeFilters.size > 0 && (
                                    <button onClick={() => onFilterChange(new Set())}
                                        className="text-xs px-2.5 py-1 rounded-full border font-medium text-red-400 border-red-300/50 hover:bg-red-50">
                                        Clear
                                    </button>
                                )}
                            </div>
                        )}
                    </div>

                    {/* ── NEARBY TAB (OSM places) ────────────────────────────── */}
                    {activeTab === 'nearby' && (
                        <div className="flex-1 overflow-y-auto px-3 py-3">
                            {/* Status bar */}
                            <div className="flex items-center justify-between mb-2">
                                <p className={`text-[10px] uppercase font-bold tracking-wider
                                    ${darkMode ? 'text-green-800' : 'text-gray-400'}`}>
                                    {userLocation ? 'Within 5 km · via OpenStreetMap' : 'Enable location to see nearby places'}
                                </p>
                                {userLocation && (
                                    <button onClick={refetchNearby} title="Refresh"
                                        className={`p-1 rounded-lg transition-colors ${darkMode ? 'text-green-600 hover:text-green-400' : 'text-gray-400 hover:text-green-600'}`}>
                                        <RefreshCw size={12} className={nearbyLoading ? 'animate-spin' : ''} />
                                    </button>
                                )}
                            </div>

                            {nearbyLoading && (
                                <div className="flex items-center gap-2 py-8 justify-center">
                                    <Loader2 size={20} className="text-green-500 animate-spin" />
                                    <span className={`text-sm ${darkMode ? 'text-green-600' : 'text-gray-400'}`}>
                                        Finding nearby green spaces…
                                    </span>
                                </div>
                            )}

                            {nearbyError && !nearbyLoading && (
                                <div className="text-xs text-red-400 bg-red-100/10 border border-red-400/20 rounded-xl px-3 py-2 mb-2">
                                    {nearbyError}
                                </div>
                            )}

                            {!nearbyLoading && !userLocation && (
                                <div className="text-center py-12">
                                    <MapPin size={36} className="mx-auto text-green-300 mb-3" />
                                    <p className={`text-sm ${darkMode ? 'text-green-600' : 'text-gray-400'}`}>
                                        Allow location access to discover nearby parks, forests and gardens
                                    </p>
                                </div>
                            )}

                            {!nearbyLoading && userLocation && filteredNearby.length === 0 && (
                                <div className="text-center py-12">
                                    <Trees size={36} className="mx-auto text-green-300 mb-3" />
                                    <p className={`text-sm ${darkMode ? 'text-green-600' : 'text-gray-400'}`}>
                                        No nearby places found
                                    </p>
                                </div>
                            )}

                            <div className="space-y-1.5">
                                {filteredNearby.map((place) => (
                                    <NearbyPlaceCard
                                        key={place.id}
                                        place={place}
                                        darkMode={darkMode}
                                        onClick={() => onNearbyClick?.(place)}
                                        isSelected={selectedNearby?.id === place.id}
                                    />
                                ))}
                            </div>
                        </div>
                    )}

                    {/* ── APP TAB (user-added spaces) ───────────────────────── */}
                    {activeTab === 'app' && (
                        <div className="flex-1 overflow-y-auto px-3 py-3 space-y-2">
                            {filtered.length === 0 && (
                                <div className="text-center py-12">
                                    <Trees size={40} className="mx-auto text-green-300 mb-3" />
                                    <p className={`text-sm ${darkMode ? 'text-green-600' : 'text-gray-400'}`}>
                                        No spaces found
                                    </p>
                                    <p className={`text-xs mt-1 ${darkMode ? 'text-green-800' : 'text-gray-300'}`}>
                                        Use + Add Space to add one!
                                    </p>
                                </div>
                            )}
                            {filtered.map((space) => (
                                <SpaceCard
                                    key={space._id}
                                    space={space}
                                    distance={formatDist(space.distKm)}
                                    onClick={() => onSelect(space)}
                                    isSelected={selectedSpace?._id === space._id}
                                    darkMode={darkMode}
                                />
                            ))}
                        </div>
                    )}
                </>
            )}
        </aside>
    );
}
